// Function to get user account from local storage or metamask
function getUserAccount() {
  try {
    // Try to get the account from local storage
    const storedAccount = localStorage.getItem('account');
    if (storedAccount) return storedAccount;

    // If not found, try to get it from MetaMask
    const accounts = await window.ethereum.request({ method: 'eth_accounts' });
    if (accounts.length > 0) {
      return accounts[0];
    } else {
      console.error('No account found');
      return null;
    }
  } catch (error) {
    console.error(error);
    return null;
  }
}

// Function to sign transaction
async function signTransaction(tx) {
  try {
    // Get the user's private key from local storage or MetaMask
    const privateKey = localStorage.getItem('privateKey');
    if (!privateKey) {
      const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
      const account = accounts[0];
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const wallet = provider.getSigner(account);
      privateKey = await wallet._signingKey().then((key) => key.privateKey);
      localStorage.setItem('privateKey', privateKey);
    }

    // Sign the transaction
    return tx.sign(privateKey);
  } catch (error) {
    console.error(error);
    return null;
  }
}

